import React, { useState, useEffect } from 'react';
import { getRooms, getRoomTypes, createRoom, updateRoom, deleteRoom, createRoomType, updateRoomType, uploadRoomImage, deleteRoomImage } from '../api';
import toast from 'react-hot-toast';

function Modal({ title, onClose, children }) {
  return (
    <div style={{ position: 'fixed', inset: 0, zIndex: 600, background: 'rgba(0,0,0,0.45)', display: 'flex', alignItems: 'center', justifyContent: 'center', padding: 24 }} onClick={onClose}>
      <div style={{ background: 'white', borderRadius: 16, width: '100%', maxWidth: 520, boxShadow: '0 24px 64px rgba(0,0,0,0.2)', maxHeight: '90vh', overflowY: 'auto' }} onClick={e => e.stopPropagation()}>
        <div style={{ padding: '20px 24px', borderBottom: '1px solid var(--gray-100)', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <h3 style={{ fontWeight: 800, fontSize: '1rem', color: 'var(--navy)' }}>{title}</h3>
          <button onClick={onClose} style={{ background: 'none', border: 'none', fontSize: '1.1rem', color: 'var(--gray-400)', cursor: 'pointer' }}>x</button>
        </div>
        <div style={{ padding: 24 }}>{children}</div>
      </div>
    </div>
  );
}

export default function RoomsPage() {
  const [rooms, setRooms]           = useState([]);
  const [roomTypes, setRoomTypes]   = useState([]);
  const [loading, setLoading]       = useState(true);
  const [tab, setTab]               = useState('rooms');
  const [modal, setModal]           = useState(null);
  const [editing, setEditing]       = useState(null);
  const [saving, setSaving]         = useState(false);
  const [filterType, setFilterType] = useState('');
  const [deletingImage, setDeletingImage] = useState(false);

  const [roomForm, setRoomForm]     = useState({ room_number: '', room_type: '', floor: '', status: 'available' });
  const [typeForm, setTypeForm]     = useState({ name: '', description: '', capacity: 2, base_price: 0, amenities: '' });
  const [imageFile, setImageFile]   = useState(null);
  const [roomImages, setRoomImages]  = useState([]);

  const load = () => {
    Promise.all([getRooms(), getRoomTypes()]).then(([r, t]) => {
      setRooms(r.data.results || r.data);
      setRoomTypes(t.data.results || t.data);
    }).finally(() => setLoading(false));
  };
  useEffect(() => { load(); }, []);

  const openAddRoom  = () => { 
    setRoomForm({ 
      room_number: '', 
      room_type: roomTypes[0]?.id || '', 
      floor: '', 
      status: 'available' 
    }); 
    setRoomImages([]);
    setImageFile(null);
    setEditing(null); 
    setModal('addRoom'); 
  };
  
  const openEditRoom = (r) => { 
    setRoomForm({ 
      room_number: r.room_number, 
      room_type: r.room_type?.id, 
      floor: r.floor, 
      status: r.status 
    }); 
    setEditing(r); 
    setModal('editRoom'); 
  };
  
  const openAddType  = () => { 
    setTypeForm({ name: '', description: '', capacity: 2, base_price: 0, amenities: '' }); 
    setEditing(null); 
    setModal('addType'); 
  };
  
  const openEditType = (t) => { 
    setTypeForm({ 
      name: t.name, 
      description: t.description, 
      capacity: t.capacity, 
      base_price: t.base_price, 
      amenities: (t.amenities || []).join(', ') 
    }); 
    setEditing(t); 
    setModal('editType'); 
  };

  const saveRoom = async () => {
    setSaving(true);
    try {
      if (!roomForm.room_number || roomForm.room_number.trim() === '') {
        toast.error('Room number is required');
        setSaving(false);
        return;
      }
      
      if (!roomForm.room_type) {
        toast.error('Room type is required');
        setSaving(false);
        return;
      }
      
      if (!roomForm.floor || roomForm.floor === '') {
        toast.error('Floor number is required');
        setSaving(false);
        return;
      }
      
      const data = { 
        room_number: roomForm.room_number.trim(),
        room_type: parseInt(roomForm.room_type),
        floor: parseInt(roomForm.floor),
        status: roomForm.status
      };
      
      let roomResponse;
      if (editing) { 
        roomResponse = await updateRoom(editing.id, data); 
        toast.success('Room updated successfully.'); 
      } else { 
        roomResponse = await createRoom(data);
        const newRoom = roomResponse.data;
        toast.success('Room created successfully.');
        
        if (roomImages.length > 0) {
          toast.loading(`Uploading ${roomImages.length} image(s)...`, { id: 'uploading' });
          
          for (let i = 0; i < roomImages.length; i++) {
            const fd = new FormData();
            fd.append('image', roomImages[i]);
            fd.append('is_primary', i === 0 ? 'true' : 'false');
            fd.append('order', i);
            
            try {
              await uploadRoomImage(newRoom.id, fd);
            } catch (uploadError) {
              console.error(`Failed to upload image ${i + 1}:`, uploadError);
              toast.error(`Failed to upload image ${i + 1}`, { id: 'uploading' });
            }
          }
          
          toast.success(`${roomImages.length} image(s) uploaded successfully!`, { id: 'uploading' });
        }
      }
      
      setModal(null); 
      load();
    } catch (e) {
      console.error('Error saving room:', e);
      console.error('Error response:', e.response);
      console.error('Error data:', e.response?.data);
      
      if (e.response?.data) {
        const errors = e.response.data;
        if (typeof errors === 'object') {
          const errorMessages = Object.entries(errors).map(([field, msgs]) => {
            if (field === 'non_field_errors') return msgs;
            return `${field}: ${Array.isArray(msgs) ? msgs.join(', ') : msgs}`;
          }).join('; ');
          toast.error(errorMessages);
        } else {
          toast.error(String(errors));
        }
      } else {
        toast.error('Failed to save room. Please check all fields.');
      }
    } finally { 
      setSaving(false); 
    }
  };

  const saveType = async () => {
    setSaving(true);
    try {
      if (!typeForm.base_price || parseFloat(typeForm.base_price) <= 0) {
        toast.error('Base price is required and must be greater than 0');
        setSaving(false);
        return;
      }
      
      if (!typeForm.name || typeForm.name.trim() === '') {
        toast.error('Room type name is required');
        setSaving(false);
        return;
      }
      
      if (!typeForm.capacity || parseInt(typeForm.capacity) <= 0) {
        toast.error('Capacity must be at least 1');
        setSaving(false);
        return;
      }
      
      const amenities = typeForm.amenities.split(',').map(a => a.trim()).filter(Boolean);
      const data = { 
        name: typeForm.name.trim().toLowerCase(),
        description: typeForm.description || '',
        capacity: parseInt(typeForm.capacity), 
        base_price: parseFloat(typeForm.base_price), 
        amenities: amenities
      };
      
      console.log('Saving room type data:', data);
      
      if (editing) { 
        await updateRoomType(editing.id, data); 
        toast.success('Room type updated successfully.'); 
      } else { 
        await createRoomType(data);              
        toast.success('Room type created successfully.'); 
      }
      setModal(null); 
      load();
    } catch (e) {
      console.error('Error saving room type:', e);
      console.error('Error response:', e.response);
      console.error('Error data:', e.response?.data);
      
      if (e.response?.data) {
        const errors = e.response.data;
        if (typeof errors === 'object') {
          const errorMessages = Object.entries(errors).map(([field, msgs]) => {
            if (field === 'non_field_errors') return msgs;
            return `${field}: ${Array.isArray(msgs) ? msgs.join(', ') : msgs}`;
          }).join('; ');
          toast.error(errorMessages);
        } else {
          toast.error(String(errors));
        }
      } else {
        toast.error('Failed to save room type.');
      }
    } finally { 
      setSaving(false); 
    }
  };

  const handleDeleteRoom = async (id) => {
    if (!window.confirm('Delete this room? This action cannot be undone.')) return;
    try { 
      await deleteRoom(id); 
      toast.success('Room deleted successfully.'); 
      load(); 
    } catch (e) { 
      const errorMsg = e.response?.data?.detail || 'Cannot delete room with existing reservations.';
      toast.error(errorMsg); 
    }
  };

  const handleDeleteImage = async (imageId) => {
    if (!window.confirm('Delete this image? This action cannot be undone.')) return;
    
    setDeletingImage(true);
    try {
      await deleteRoomImage(editing.id, imageId);
      toast.success('Image deleted successfully.');
      
      // Update the local editing state to remove the deleted image
      setEditing(prev => ({
        ...prev,
        images: prev.images.filter(img => img.id !== imageId)
      }));
      
      // Reload rooms to refresh the image count
      load();
    } catch (e) {
      console.error('Error deleting image:', e);
      toast.error(e.response?.data?.detail || 'Failed to delete image.');
    } finally {
      setDeletingImage(false);
    }
  };

  const saveImage = async () => {
    if (!imageFile) {
      toast.error('Please select an image file.');
      return;
    }
    
    setSaving(true);
    try {
      const fd = new FormData(); 
      fd.append('image', imageFile); 
      fd.append('is_primary', editing.images?.length === 0 ? 'true' : 'false'); 
      fd.append('order', editing.images?.length || 0);
      await uploadRoomImage(editing.id, fd);
      toast.success('Image uploaded successfully.'); 
      setImageFile(null); 
      load(); // Reload to update image list
    } catch (e) { 
      console.error('Upload error:', e);
      toast.error(e.response?.data?.detail || 'Upload failed. Image may be too large or invalid format.'); 
    } finally { 
      setSaving(false); 
    }
  };

  const handleAddImage = (e) => {
    const file = e.target.files[0];
    if (file) {
      if (roomImages.length >= 5) {
        toast.error('Maximum 5 images per room');
        return;
      }
      setRoomImages([...roomImages, file]);
      toast.success(`Image ${roomImages.length + 1} added`);
    }
  };

  const removeImage = (index) => {
    setRoomImages(roomImages.filter((_, i) => i !== index));
    toast.success('Image removed');
  };

  const filtered = filterType ? rooms.filter(r => r.room_type?.name === filterType) : rooms;

  return (
    <div style={{ padding: 32 }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 24 }}>
        <div>
          <h1 style={{ fontSize: '1.5rem', fontWeight: 800, color: 'var(--navy)', letterSpacing: '-0.02em' }}>Room Management</h1>
          <p style={{ fontSize: '0.85rem', color: 'var(--gray-400)', marginTop: 2 }}>Manage rooms and room types</p>
        </div>
        <div style={{ display: 'flex', gap: 10 }}>
          <button className="btn btn-outline" onClick={openAddType}>+ Add Room Type</button>
          <button className="btn btn-primary" onClick={openAddRoom}>+ Add Room</button>
        </div>
      </div>

      {/* Tabs */}
      <div style={{ display: 'flex', gap: 0, marginBottom: 20, borderBottom: '2px solid var(--gray-100)' }}>
        {[['rooms', 'Rooms'], ['types', 'Room Types']].map(([key, label]) => (
          <button 
            key={key} 
            onClick={() => setTab(key)} 
            style={{ 
              padding: '10px 20px', 
              border: 'none', 
              background: 'none', 
              fontSize: '0.875rem', 
              fontWeight: 600, 
              cursor: 'pointer', 
              color: tab === key ? 'var(--blue)' : 'var(--gray-400)', 
              borderBottom: tab === key ? '2px solid var(--blue)' : '2px solid transparent', 
              marginBottom: -2, 
              transition: 'color 0.2s' 
            }}
          >
            {label}
          </button>
        ))}
      </div>

      {tab === 'rooms' && (
        <>
          <div style={{ display: 'flex', gap: 8, marginBottom: 16, flexWrap: 'wrap' }}>
            {['', ...roomTypes.map(t => t.name)].map(type => (
              <button 
                key={type} 
                onClick={() => setFilterType(type)} 
                style={{ 
                  padding: '6px 14px', 
                  borderRadius: 8, 
                  border: 'none', 
                  cursor: 'pointer', 
                  fontSize: '0.78rem', 
                  fontWeight: 600, 
                  background: filterType === type ? 'var(--blue)' : 'var(--gray-100)', 
                  color: filterType === type ? 'white' : 'var(--gray-600)', 
                  textTransform: 'capitalize', 
                  transition: 'all 0.2s' 
                }}
              >
                {type || 'All'}
              </button>
            ))}
          </div>
          <div className="card">
            {loading ? <div style={{ padding: 40, textAlign: 'center', color: 'var(--gray-400)' }}>Loading...</div> : (
              <table className="table">
                <thead>
                  <tr>
                    <th>Room No.</th>
                    <th>Type</th>
                    <th>Floor</th>
                    <th>Status</th>
                    <th>Price/Night</th>
                    <th>Images</th>
                    <th>Actions</th>
                  </tr>
                </thead>
                <tbody>
                  {filtered.map(r => (
                    <tr key={r.id}>
                      <td><span style={{ fontWeight: 700 }}>{r.room_number}</span></td>
                      <td><span style={{ textTransform: 'capitalize' }}>{r.room_type?.name}</span></td>
                      <td>Floor {r.floor}</td>
                      <td><span className={`badge badge-${r.status}`}>{r.status}</span></td>
                      <td>PHP {Number(r.room_type?.base_price).toLocaleString()}</td>
                      <td>
                        <button 
                          className="btn btn-sm btn-outline" 
                          onClick={() => { setEditing(r); setModal('images'); }}
                        >
                          Images {r.images?.length || 0}
                        </button>
                      </td>
                      <td>
                        <div style={{ display: 'flex', gap: 6 }}>
                          <button className="btn btn-sm btn-outline" onClick={() => openEditRoom(r)}>Edit</button>
                          <button className="btn btn-sm btn-danger" onClick={() => handleDeleteRoom(r.id)}>Delete</button>
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            )}
          </div>
        </>
      )}

      {tab === 'types' && (
        <div className="card">
          <table className="table">
            <thead>
              <tr>
                <th>Name</th>
                <th>Capacity</th>
                <th>Base Price</th>
                <th>Amenities</th>
                <th>Actions</th>
              </tr>
            </thead>
            <tbody>
              {roomTypes.map(t => (
                <tr key={t.id}>
                  <td style={{ textTransform: 'capitalize', fontWeight: 600 }}>{t.name}</td>
                  <td>Up to {t.capacity} guests</td>
                  <td>PHP {Number(t.base_price).toLocaleString()}/night</td>
                  <td style={{ fontSize: '0.8rem', color: 'var(--gray-600)' }}>{(t.amenities || []).join(', ') || '-'}</td>
                  <td><button className="btn btn-sm btn-outline" onClick={() => openEditType(t)}>Edit</button></td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {/* Room Form Modal */}
      {(modal === 'addRoom' || modal === 'editRoom') && (
        <Modal title={modal === 'addRoom' ? 'Add New Room' : 'Edit Room'} onClose={() => setModal(null)}>
          <div style={{ display: 'flex', flexDirection: 'column', gap: 14 }}>
            <div className="form-group">
              <label>Room Number <span style={{ color: 'red' }}>*</span></label>
              <input 
                placeholder="e.g. 101" 
                value={roomForm.room_number} 
                onChange={e => setRoomForm(f => ({ ...f, room_number: e.target.value }))} 
              />
            </div>
            <div className="form-group">
              <label>Room Type <span style={{ color: 'red' }}>*</span></label>
              <select 
                value={roomForm.room_type} 
                onChange={e => setRoomForm(f => ({ ...f, room_type: e.target.value }))}
              >
                <option value="">Select room type</option>
                {roomTypes.map(t => <option key={t.id} value={t.id}>{t.name}</option>)}
              </select>
            </div>
            <div className="form-group">
              <label>Floor <span style={{ color: 'red' }}>*</span></label>
              <input 
                type="number" 
                placeholder="1" 
                value={roomForm.floor} 
                onChange={e => setRoomForm(f => ({ ...f, floor: e.target.value }))} 
              />
            </div>
            <div className="form-group">
              <label>Status</label>
              <select 
                value={roomForm.status} 
                onChange={e => setRoomForm(f => ({ ...f, status: e.target.value }))}
              >
                <option value="available">Available</option>
                <option value="occupied">Occupied</option>
                <option value="maintenance">Maintenance</option>
              </select>
            </div>

            {modal === 'addRoom' && (
              <div className="form-group">
                <label>Room Images (Optional, max 5)</label>
                <input 
                  type="file" 
                  accept="image/*" 
                  onChange={handleAddImage}
                  style={{ padding: 8, marginBottom: 10 }}
                  disabled={roomImages.length >= 5}
                />
                {roomImages.length > 0 && (
                  <div style={{ marginTop: 10 }}>
                    <label>Selected Images ({roomImages.length}/5):</label>
                    <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap', marginTop: 8 }}>
                      {roomImages.map((img, idx) => (
                        <div key={idx} style={{ position: 'relative' }}>
                          <img 
                            src={URL.createObjectURL(img)} 
                            alt={`Preview ${idx + 1}`} 
                            style={{ width: 60, height: 60, objectFit: 'cover', borderRadius: 6 }}
                          />
                          <button
                            onClick={() => removeImage(idx)}
                            style={{
                              position: 'absolute',
                              top: -8,
                              right: -8,
                              background: 'red',
                              color: 'white',
                              border: 'none',
                              borderRadius: '50%',
                              width: 20,
                              height: 20,
                              cursor: 'pointer',
                              fontSize: 12,
                              display: 'flex',
                              alignItems: 'center',
                              justifyContent: 'center'
                            }}
                          >
                            x
                          </button>
                        </div>
                      ))}
                    </div>
                  </div>
                )}
                <small style={{ color: 'var(--gray-400)', fontSize: '0.7rem' }}>
                  You can upload up to 5 images. First image will be primary.
                </small>
              </div>
            )}
            
            <div style={{ display: 'flex', gap: 10, marginTop: 8 }}>
              <button className="btn btn-outline" style={{ flex: 1, justifyContent: 'center' }} onClick={() => setModal(null)}>Cancel</button>
              <button className="btn btn-primary" style={{ flex: 2, justifyContent: 'center' }} onClick={saveRoom} disabled={saving}>
                {saving ? 'Saving...' : 'Save Room'}
              </button>
            </div>
          </div>
        </Modal>
      )}

      {/* Room Type Modal */}
      {(modal === 'addType' || modal === 'editType') && (
        <Modal title={modal === 'addType' ? 'Add Room Type' : 'Edit Room Type'} onClose={() => setModal(null)}>
          <div style={{ display: 'flex', flexDirection: 'column', gap: 14 }}>
            <div className="form-group">
              <label>Type Name <span style={{ color: 'red' }}>*</span></label>
              <input 
                type="text"
                placeholder="e.g., Standard, Deluxe, Suite, Family Room, etc."
                value={typeForm.name} 
                onChange={e => setTypeForm(f => ({ ...f, name: e.target.value }))}
                style={{ textTransform: 'capitalize' }}
              />
              <small style={{ color: 'var(--gray-400)', fontSize: '0.7rem' }}>
                Enter any custom room type name
              </small>
            </div>
            
            <div className="form-group">
              <label>Description</label>
              <textarea 
                rows={3} 
                value={typeForm.description} 
                onChange={e => setTypeForm(f => ({ ...f, description: e.target.value }))} 
                style={{ resize: 'vertical' }} 
                placeholder="Optional description of the room type"
              />
            </div>
            
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 12 }}>
              <div className="form-group">
                <label>Capacity (guests) <span style={{ color: 'red' }}>*</span></label>
                <input 
                  type="number" 
                  min={1} 
                  value={typeForm.capacity} 
                  onChange={e => setTypeForm(f => ({ ...f, capacity: e.target.value }))} 
                  required
                />
              </div>
              <div className="form-group">
                <label>Base Price (PHP) <span style={{ color: 'red' }}>*</span></label>
                <input 
                  type="number" 
                  min={0} 
                  step="0.01"
                  value={typeForm.base_price} 
                  onChange={e => setTypeForm(f => ({ ...f, base_price: e.target.value }))} 
                  required
                  placeholder="0.00"
                />
              </div>
            </div>
            
            <div className="form-group">
              <label>Amenities (comma separated)</label>
              <input 
                placeholder="WiFi, TV, Air Conditioning, Mini Bar" 
                value={typeForm.amenities} 
                onChange={e => setTypeForm(f => ({ ...f, amenities: e.target.value }))} 
              />
              <small style={{ color: 'var(--gray-400)', fontSize: '0.7rem' }}>Separate multiple amenities with commas</small>
            </div>
            
            <div style={{ display: 'flex', gap: 10, marginTop: 8 }}>
              <button className="btn btn-outline" style={{ flex: 1, justifyContent: 'center' }} onClick={() => setModal(null)}>Cancel</button>
              <button className="btn btn-primary" style={{ flex: 2, justifyContent: 'center' }} onClick={saveType} disabled={saving}>
                {saving ? 'Saving...' : (modal === 'addType' ? 'Create Type' : 'Update Type')}
              </button>
            </div>
          </div>
        </Modal>
      )}

      {/* Image Upload Modal with Delete Buttons */}
      {modal === 'images' && editing && (
        <Modal title={`Images - Room ${editing.room_number}`} onClose={() => { setModal(null); setImageFile(null); }}>
          <div style={{ marginBottom: 20 }}>
            <div style={{ display: 'flex', gap: 12, flexWrap: 'wrap', marginBottom: 12 }}>
              {(editing.images || []).length === 0 ? 
                <p style={{ color: 'var(--gray-400)', fontSize: '0.85rem' }}>No images yet.</p> :
                editing.images.map(img => (
                  <div key={img.id} style={{ position: 'relative', width: 120, borderRadius: 8, overflow: 'hidden', border: '1px solid var(--gray-200)' }}>
                    <img 
                      src={img.image} 
                      alt="" 
                      style={{ width: '100%', height: 90, objectFit: 'cover' }} 
                    />
                    <button
                      onClick={() => handleDeleteImage(img.id)}
                      disabled={deletingImage}
                      style={{
                        position: 'absolute',
                        top: 4,
                        right: 4,
                        background: 'red',
                        color: 'white',
                        border: 'none',
                        borderRadius: '50%',
                        width: 24,
                        height: 24,
                        cursor: 'pointer',
                        fontSize: 14,
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        opacity: 0.9
                      }}
                      title="Delete image"
                    >
                      x
                    </button>
                    {img.is_primary && (
                      <div style={{
                        position: 'absolute',
                        bottom: 4,
                        left: 4,
                        background: 'rgba(0,0,0,0.7)',
                        color: 'white',
                        fontSize: '10px',
                        padding: '2px 6px',
                        borderRadius: 4
                      }}>
                        Primary
                      </div>
                    )}
                  </div>
                ))
              }
            </div>
            <div style={{ marginTop: 16 }}>
              <p style={{ fontSize: '0.8rem', color: 'var(--gray-500)', marginBottom: 8 }}>
                Current: {(editing.images || []).length}/5 images
              </p>
            </div>
          </div>
          <div className="form-group" style={{ marginBottom: 16 }}>
            <label>Upload New Image (max 5 total)</label>
            <input 
              type="file" 
              accept="image/*" 
              onChange={e => setImageFile(e.target.files[0])} 
              style={{ padding: 8 }} 
              disabled={(editing.images || []).length >= 5}
            />
            {(editing.images || []).length >= 5 && (
              <small style={{ color: 'red', fontSize: '0.7rem' }}>
                Maximum 5 images reached. Delete an image to upload more.
              </small>
            )}
          </div>
          <button 
            className="btn btn-primary" 
            style={{ width: '100%', justifyContent: 'center' }} 
            onClick={saveImage} 
            disabled={saving || !imageFile || (editing.images || []).length >= 5}
          >
            {saving ? 'Uploading...' : 'Upload Image'}
          </button>
        </Modal>
      )}
    </div>
  );
}
